import React from "react";

import AmountDisplay from "@/components/primitives/AmountDisplay";
import EmptyState from "@/components/primitives/EmptyState";
import { useZaps } from "@/hooks/useZaps";
import Loader from "@/components/primitives/Loader";
import { truncateAddress } from "@/utils/format";

interface RecentZapsProps {
  address: string;
}

function formatTipAge(seconds: number): string {
  const nowSec = Math.floor(Date.now() / 1000);
  const diff = Math.max(0, nowSec - seconds);
  if (diff < 60) return "Just now";
  if (diff < 3600) {
    const m = Math.floor(diff / 60);
    return `${m} min ago`;
  }
  if (diff < 86400) {
    const h = Math.floor(diff / 3600);
    return `${h} hr ago`;
  }
  const d = Math.floor(diff / 86400);
  return `${d} day${d === 1 ? "" : "s"} ago`;
}

const RecentZaps: React.FC<RecentZapsProps> = ({ address }) => {
  const { tips, loading } = useZaps(address, "creator", 3);

  if (loading && tips.length === 0) {
    return (
      <div className="flex justify-center py-10">
        <Loader size="sm" />
      </div>
    );
  }

  if (tips.length === 0) {
    return (
      <EmptyState
        title="No tips yet"
        description="When someone supports this creator, the latest tips show up here."
      />
    );
  }

  return (
    <ul className="space-y-4">
      {tips.map((tip) => (
        <li
          key={tip.id}
          className="rounded-xl border border-zap-border bg-zap-bg-alt/60 p-4 dark:bg-zap-bg/30"
        >
          <div className="flex flex-wrap items-start justify-between gap-3">
            <div className="min-w-0">
              <p className="text-[11px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted">
                From wallet
              </p>
              <p
                className="mt-1 font-mono text-sm font-medium text-zap-ink"
                title={tip.tipper}
              >
                {truncateAddress(tip.tipper, 5)}
              </p>
            </div>
            <div className="shrink-0 text-right">
              <AmountDisplay amount={tip.amount} className="text-base" />
              <p className="mt-1 text-[10px] font-medium uppercase tracking-[0.1em] text-zap-ink-faint">
                {formatTipAge(tip.timestamp)}
              </p>
            </div>
          </div>
          <div className="mt-3 border-t border-dashed border-zap-border pt-3">
            <p className="text-[10px] font-semibold uppercase tracking-[0.12em] text-zap-ink-muted">
              Message
            </p>
            <p className="mt-1.5 text-sm font-medium leading-relaxed text-zap-ink">
              {tip.message?.trim()
                ? `“${tip.message.trim()}”`
                : "No message with this tip."}
            </p>
          </div>
        </li>
      ))}
    </ul>
  );
};

export default RecentZaps;
